import emailjs from '@emailjs/browser';

// Credentials from the provided reference
const PUBLIC_KEY = 'haEhYz7iGgrGEu0kP';
const SERVICE_ID = 'service_om6q4kc';
const TEMPLATE_ID = 'template_8gw6alr';

export const initEmailService = () => {
  emailjs.init(PUBLIC_KEY);
};

export const sendApprovalEmail = async (toName: string, toEmail: string, course: string) => {
  try {
    const templateParams = {
      to_name: toName,
      to_email: toEmail,
      course: course,
      from_name: 'Laguna University Alumni System',
      message: `Congratulations! Your alumni account has been approved. You can now log in to the Alumni Tracer System to update your profile and employment status.`,
      subject: 'Alumni Account Approved',
      reply_to: 'alumni@lagunauniversity.edu.ph'
    };

    const response = await emailjs.send(
      SERVICE_ID,
      TEMPLATE_ID,
      templateParams
    );

    return { success: true, response };
  } catch (error) {
    console.error('EmailJS Error:', error);
    return { success: false, error };
  }
};

import React, { useState, useEffect } from 'react';
import { CheckCircle, Search, Calendar, Settings, AlertCircle, Loader2, Mail, CheckSquare, Square, X } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { Student } from '../types';
import { sendApprovalEmail, initEmailService } from '../services/emailService';

interface ApprovalWorkflowProps {
  onUpdate: () => void;
}

const ApprovalWorkflow: React.FC<ApprovalWorkflowProps> = ({ onUpdate }) => {
  const [students, setStudents] = useState<Student[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Modal States
  const [showConfirmModal, setShowConfirmModal] = useState(false);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [processing, setProcessing] = useState(false);

  // Auto-Approval Config State
  const [autoDate, setAutoDate] = useState('');
  const [autoYear, setAutoYear] = useState(new Date().getFullYear().toString());
  const [isAutoEnabled, setIsAutoEnabled] = useState(false);

  useEffect(() => {
    initEmailService();
    fetchCandidates();
    loadAutoConfig();
  }, []);

  const loadAutoConfig = () => {
    const savedConfig = localStorage.getItem('lu_auto_approval_config');
    if (savedConfig) {
      const config = JSON.parse(savedConfig);
      setAutoDate(config.date);
      setAutoYear(config.year);
      setIsAutoEnabled(config.enabled);

      // Check if we should run auto-approval now
      if (config.enabled && config.date) {
        const targetDate = new Date(config.date);
        const today = new Date();
        if (today >= targetDate) {
          runAutoApproval(config.year);
        }
      }
    }
  };

  const saveAutoConfig = () => {
    const config = { date: autoDate, year: autoYear, enabled: true };
    localStorage.setItem('lu_auto_approval_config', JSON.stringify(config));
    setIsAutoEnabled(true);
    setShowConfigModal(false);
    alert(`Auto-approval scheduled for ${autoDate}`);
  };

  const fetchCandidates = async () => {
    setLoading(true);
    // Fetch only users from 'students' table who are 'Graduating' and NOT yet 'Alumni'
    // Assuming 'enrollment_status' stores this.
    const { data, error } = await supabase
      .from('students')
      .select('*')
      .neq('enrollment_status', 'Alumni') 
      .order('last_name', { ascending: true });

    if (!error && data) {
      setStudents(data as Student[]);
    }
    setLoading(false);
  };

  const handleSelectAll = () => {
    if (selectedIds.size === students.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(students.map(s => s.id!)));
    }
  };

  const handleSelectOne = (id: string) => {
    const newSet = new Set(selectedIds);
    if (newSet.has(id)) newSet.delete(id);
    else newSet.add(id);
    setSelectedIds(newSet);
  };

  const runAutoApproval = async (targetYear: string) => {
    console.log("Running Auto Approval...");
    // Fetch all eligible
    const { data } = await supabase
      .from('students')
      .select('*')
      .neq('enrollment_status', 'Alumni');

    if (data && data.length > 0) {
      const ids = data.map(s => s.id);
      await executeApproval(ids, targetYear, true);
      // Disable auto-approval after running to prevent loops
      const config = { date: autoDate, year: autoYear, enabled: false };
      localStorage.setItem('lu_auto_approval_config', JSON.stringify(config));
      setIsAutoEnabled(false);
    }
  };

  const executeApproval = async (ids: string[], targetYear: string, isAuto = false) => {
    setProcessing(true);
    let successCount = 0;

    // Filter students to approve
    const targets = students.filter(s => ids.includes(s.id!)) || [];

    // In auto mode, we might need to fetch students if 'students' state isn't populated yet
    // simplified for this context assuming 'students' is populated or using the passed IDs if needed.

    try {
      // 1. Update Database
      const { error } = await supabase
        .from('students')
        .update({ 
          enrollment_status: 'Alumni',
          year_level: targetYear 
        })
        .in('id', ids);

      if (error) throw error;

      // 2. Send Emails
      for (const student of targets) {
        if (student.email) {
          await sendApprovalEmail(
            `${student.first_name} ${student.last_name}`,
            student.email,
            student.program
          );
          successCount++;
        }
      }

      if (!isAuto) {
        alert(`Successfully approved ${ids.length} students. Sent ${successCount} emails.`);
        setShowConfirmModal(false);
        setSelectedIds(new Set());
        fetchCandidates();
        onUpdate(); // Refresh parent if needed
      } else {
        console.log(`Auto-approved ${ids.length} students.`);
        fetchCandidates();
      }

    } catch (err: any) {
      console.error("Approval Error:", err);
      if (!isAuto) alert("Failed to approve students: " + err.message);
    } finally {
      setProcessing(false);
    }
  };

  const filteredStudents = students.filter(student => 
    student.last_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.first_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.student_number.includes(searchTerm)
  );

  return (
    <div className="animate-fade-in space-y-6">

       {/* Actions Bar */}
       <div className="bg-white/60 backdrop-blur-xl rounded-3xl p-6 border border-white/50 shadow-sm flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4 w-full md:w-auto">
             <div className="relative flex-grow md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
                <input 
                  type="text" 
                  placeholder="Search candidates..." 
                  value={searchTerm}
                  onChange={e => setSearchTerm(e.target.value)}
                  className="w-full pl-9 pr-4 py-2.5 bg-white rounded-xl border border-gray-200 text-sm focus:ring-2 focus:ring-luGreen/20 outline-none"
                />
             </div>
          </div>

          <div className="flex items-center gap-3 w-full md:w-auto">
             <button 
               onClick={() => setShowConfigModal(true)}
               className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-bold transition-all border ${isAutoEnabled ? 'bg-indigo-50 text-indigo-600 border-indigo-200' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}
             >
                <Settings size={16} />
                {isAutoEnabled ? 'Auto-Approval On' : 'Configure Auto'}
             </button>

             <button 
               onClick={() => setShowConfirmModal(true)}
               disabled={selectedIds.size === 0}
               className="flex-grow md:flex-initial flex items-center justify-center gap-2 px-6 py-2.5 bg-gradient-to-r from-luGreen to-emerald-600 text-white rounded-xl text-sm font-bold shadow-lg shadow-green-200 hover:shadow-xl hover:-translate-y-0.5 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
             >
                <CheckCircle size={18} />
                Approve Selected ({selectedIds.size})
             </button>
          </div>
       </div>

       {/* Candidates Table */}
       <div className="bg-white/60 backdrop-blur-xl rounded-3xl border border-white/50 shadow-sm overflow-hidden">
          <div className="overflow-x-auto">
             <table className="w-full text-left border-collapse">
                <thead className="bg-gray-50/50 border-b border-gray-100">
                   <tr>
                      <th className="px-6 py-4 w-12">
                         <button onClick={handleSelectAll} className="text-gray-400 hover:text-luGreen">
                            {selectedIds.size > 0 && selectedIds.size === students.length ? <CheckSquare size={20} /> : <Square size={20} />}
                         </button>
                      </th>
                      <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Candidate</th>
                      <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Program</th>
                      <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">ID Number</th>
                      <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider text-right">Status</th>
                   </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                   {loading ? (
                      <tr><td colSpan={5} className="px-6 py-12 text-center text-gray-400">Loading candidates...</td></tr>
                   ) : filteredStudents.length === 0 ? (
                      <tr><td colSpan={5} className="px-6 py-12 text-center text-gray-400">No candidates found for approval.</td></tr>
                   ) : (
                      filteredStudents.map(student => (
                         <tr key={student.id} className={`hover:bg-green-50/50 transition-colors cursor-pointer ${selectedIds.has(student.id!) ? 'bg-green-50/30' : ''}`} onClick={() => handleSelectOne(student.id!)}>
                            <td className="px-6 py-4">
                               <button onClick={(e) => { e.stopPropagation(); handleSelectOne(student.id!); }} className={`${selectedIds.has(student.id!) ? 'text-luGreen' : 'text-gray-300'}`}>
                                  {selectedIds.has(student.id!) ? <CheckSquare size={20} /> : <Square size={20} />}
                               </button>
                            </td>
                            <td className="px-6 py-4">
                               <div className="font-bold text-gray-800">{student.last_name}, {student.first_name}</div>
                               <div className="text-xs text-gray-500">{student.email}</div>
                            </td>
                            <td className="px-6 py-4 text-sm font-medium text-gray-600">{student.program}</td>
                            <td className="px-6 py-4 text-sm font-mono text-gray-500">{student.student_number}</td>
                            <td className="px-6 py-4 text-right">
                               <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-bold bg-amber-100 text-amber-800">
                                  Needs Approval
                               </span>
                            </td>
                         </tr>
                      ))
                   )}
                </tbody>
             </table>
          </div>
       </div>

       {/* Confirm Approval Modal */}
       {showConfirmModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
             <div className="absolute inset-0 bg-gray-900/40 backdrop-blur-sm" onClick={() => setShowConfirmModal(false)}></div>
             <div className="bg-white/90 backdrop-blur-2xl rounded-3xl shadow-2xl w-full max-w-md relative z-10 p-8 border border-white/50 animate-in zoom-in-95">
                <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6 text-luGreen">
                   <Mail size={32} />
                </div>
                <h3 className="text-2xl font-bold text-center text-gray-800 mb-2">Confirm Approval</h3>
                <p className="text-center text-gray-500 mb-6">
                   Are you sure you want to approve <strong>{selectedIds.size} student(s)</strong>? 
                   This will update their status to <strong>Alumni</strong> and send a notification email.
                </p>
                <div className="flex gap-3">
                   <button 
                     onClick={() => setShowConfirmModal(false)}
                     disabled={processing}
                     className="flex-1 py-3 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold rounded-xl transition-colors"
                   >
                      Cancel
                   </button>
                   <button 
                     onClick={() => executeApproval(Array.from(selectedIds), new Date().getFullYear().toString())}
                     disabled={processing}
                     className="flex-1 py-3 bg-luGreen hover:bg-emerald-600 text-white font-bold rounded-xl shadow-lg transition-all flex items-center justify-center gap-2"
                   >
                      {processing ? <Loader2 className="animate-spin" size={20} /> : 'Yes, Approve'}
                   </button>
                </div>
             </div>
          </div>
       )}

       {/* Auto-Approval Config Modal */}
       {showConfigModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
             <div className="absolute inset-0 bg-gray-900/40 backdrop-blur-sm" onClick={() => setShowConfigModal(false)}></div>
             <div className="bg-white/90 backdrop-blur-2xl rounded-3xl shadow-2xl w-full max-w-md relative z-10 p-8 border border-white/50 animate-in zoom-in-95">
                <div className="flex justify-between items-center mb-6">
                   <h3 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                      <Settings className="text-indigo-500" /> Auto-Approval
                   </h3>
                   <button onClick={() => setShowConfigModal(false)} className="text-gray-400 hover:text-red-500"><X size={24} /></button>
                </div>

                <div className="space-y-4 mb-8">
                   <div className="bg-indigo-50 p-4 rounded-xl text-xs text-indigo-700 leading-relaxed border border-indigo-100">
                      When the scheduled date is reached, all "Graduating" students will automatically be converted to "Alumni" status and receive notification emails.
                   </div>

                   <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Scheduled Date</label>
                      <input 
                         type="date" 
                         value={autoDate}
                         onChange={e => setAutoDate(e.target.value)}
                         className="w-full px-4 py-3 bg-white rounded-xl border border-gray-200 font-bold text-gray-700 focus:ring-2 focus:ring-indigo-200 outline-none"
                      />
                   </div>

                   <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Target Alumni Year</label>
                      <input 
                         type="text" 
                         value={autoYear}
                         onChange={e => setAutoYear(e.target.value)}
                         className="w-full px-4 py-3 bg-white rounded-xl border border-gray-200 font-bold text-gray-700 focus:ring-2 focus:ring-indigo-200 outline-none"
                      />
                   </div>
                </div>

                <button 
                  onClick={saveAutoConfig}
                  className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl shadow-lg shadow-indigo-200 transition-all flex items-center justify-center gap-2"
                >
                   Save Configuration
                </button>
             </div>
          </div>
       )}

    </div>
  );
};

export default ApprovalWorkflow;

import React, { useState, useEffect } from 'react';
import { GraduationCap, Users, Search, RefreshCw, CheckCircle2 } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { Student } from '../types';
import ApprovalWorkflow from './ApprovalWorkflow';

const UserManagement: React.FC = () => {
  // Filters: 'graduating' -> New Alumni, 'alumni' -> Old Alumni, 'approval' -> Approval Workflow
  const [userFilter, setUserFilter] = useState<'graduating' | 'alumni' | 'approval'>('graduating');
  const [students, setStudents] = useState<Student[]>([]);
  const [loadingUsers, setLoadingUsers] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const fetchUsers = async () => {
    if (userFilter === 'approval') return; // Handled by child component

    setLoadingUsers(true);
    const table = userFilter === 'graduating' ? 'students' : 'alumni';

    let query = supabase.from(table).select('*').order('last_name', { ascending: true });

    // If viewing 'New Alumni' (students table), we might want to see those who are already approved or all?
    // The prompt says "New Alumni" was "Graduating". Usually 'students' table.
    // However, if we filter by status in Approval, we should just show the table as is for now,
    // or maybe filter by enrollment_status='Alumni' if we strictly want to show "New Alumni" who ARE alumni.
    // For backward compatibility and minimal logic change in viewing, we keep standard fetch but maybe indicate status.

    const { data, error } = await query;

    if (!error && data) {
      setStudents(data as Student[]);
    }
    setLoadingUsers(false);
  };

  useEffect(() => {
    fetchUsers();
  }, [userFilter]);

  const filteredStudents = students.filter(student => 
    student.last_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.first_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.student_number.includes(searchTerm)
  );

  return (
    <div className="space-y-6 animate-fade-in pb-10">
        {/* Header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div>
                <h2 className="text-2xl font-bold text-gray-800 font-display">User Management</h2>
                <p className="text-gray-500">View and manage student and alumni records.</p>
            </div>

            {/* Stats Tabs */}
            <div className="bg-white p-1 rounded-xl border border-gray-200 shadow-sm flex flex-wrap gap-1">
                <button 
                    onClick={() => setUserFilter('graduating')}
                    className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${userFilter === 'graduating' ? 'bg-green-50 text-luGreen shadow-sm' : 'text-gray-500 hover:text-gray-900'}`}
                >
                    <GraduationCap size={16} /> New Alumni
                </button>
                <button 
                    onClick={() => setUserFilter('alumni')}
                    className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${userFilter === 'alumni' ? 'bg-amber-50 text-amber-600 shadow-sm' : 'text-gray-500 hover:text-gray-900'}`}
                >
                    <Users size={16} /> Old Alumni
                </button>
                <button 
                    onClick={() => setUserFilter('approval')}
                    className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${userFilter === 'approval' ? 'bg-indigo-50 text-indigo-600 shadow-sm' : 'text-gray-500 hover:text-gray-900'}`}
                >
                    <CheckCircle2 size={16} /> Approval
                </button>
            </div>
        </div>

        {/* Conditional Rendering */}
        {userFilter === 'approval' ? (
            <ApprovalWorkflow onUpdate={() => {}} />
        ) : (
            /* Standard Table Section */
            <div className="bg-white rounded-3xl shadow-sm border border-gray-200 overflow-hidden">
                {/* Toolbar */}
                <div className="p-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-center gap-4">
                    <h2 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                        {userFilter === 'graduating' ? 'New Alumni Records' : 'Old Alumni Records'}
                        <span className="bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full text-xs">{filteredStudents.length}</span>
                    </h2>
                    <div className="flex items-center gap-3 w-full sm:w-auto">
                        <div className="relative flex-1 sm:flex-initial">
                            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
                            <input 
                                type="text" 
                                placeholder="Search name or ID..." 
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="pl-9 pr-4 py-2 rounded-xl bg-gray-50 border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-luGreen/20 focus:border-luGreen w-full sm:w-64"
                            />
                        </div>
                        <button 
                            onClick={fetchUsers}
                            className="p-2 bg-gray-50 hover:bg-gray-100 text-gray-600 rounded-xl border border-gray-200 transition-colors"
                            title="Refresh Data"
                        >
                            <RefreshCw className={`w-4 h-4 ${loadingUsers ? 'animate-spin' : ''}`} />
                        </button>
                    </div>
                </div>

                {/* Table */}
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-gray-50/50 border-b border-gray-100 text-xs uppercase tracking-wider text-gray-500 font-semibold">
                                <th className="px-6 py-4">Student Info</th>
                                <th className="px-6 py-4">Program</th>
                                <th className="px-6 py-4">Contact</th>
                                <th className="px-6 py-4">Batch/Year</th>
                                <th className="px-6 py-4 text-right">Status</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-50">
                            {loadingUsers ? (
                                <tr>
                                    <td colSpan={5} className="px-6 py-12 text-center text-gray-400">
                                        <div className="flex flex-col items-center">
                                            <RefreshCw className="w-6 h-6 animate-spin mb-2" />
                                            Loading records...
                                        </div>
                                    </td>
                                </tr>
                            ) : filteredStudents.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="px-6 py-12 text-center text-gray-400">
                                        No records found matching your search.
                                    </td>
                                </tr>
                            ) : (
                                filteredStudents.map((student, index) => (
                                    <tr key={index} className="hover:bg-gray-50/80 transition-colors group">
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col">
                                                <span className="font-bold text-gray-900">{student.last_name}, {student.first_name}</span>
                                                <span className="text-xs text-luGreen font-mono mt-0.5">{student.student_number}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className="text-sm font-medium text-gray-700">{student.program}</span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col text-sm text-gray-600">
                                                <span>{student.email || 'N/A'}</span>
                                                <span className="text-xs text-gray-400">{student.contact_no}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-50 text-blue-800">
                                                {student.year_level}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-bold uppercase tracking-wide ${
                                                student.enrollment_status === 'Alumni' 
                                                ? 'bg-purple-100 text-purple-700'
                                                : (userFilter === 'graduating' ? 'bg-green-100 text-luGreen-dark' : 'bg-amber-100 text-amber-800')
                                            }`}>
                                                {student.enrollment_status === 'Alumni' ? 'Alumni' : (userFilter === 'graduating' ? 'Graduating' : 'Graduate')}
                                            </span>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        )}
    </div>
  );
};

export default UserManagement;

import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabaseClient';
import { extractDataFromDocument, extractDataFromID } from '../services/geminiService';
import { Student, ExtractedData, UserType, Admin } from '../types';
import FileUpload from './FileUpload';
import { Eye, EyeOff, CheckCircle, AlertCircle, Loader2, XCircle, ArrowRight, ShieldCheck, Edit2, GraduationCap, User, ArrowLeft, Users, HelpCircle, FileText, ScanLine, Lock } from 'lucide-react';

interface AuthPageProps {
  onLoginSuccess: (student: Student) => void;
  onAdminLoginSuccess: (admin: Admin) => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ onLoginSuccess, onAdminLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);

  // Login Success Animation State
  const [showSuccessAnim, setShowSuccessAnim] = useState(false);
  const [loggedInStudentName, setLoggedInStudentName] = useState('');

  // Admin State
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');

  // Login State
  const [loginType, setLoginType] = useState<'student' | 'alumni'>('student');
  const [studentNumberLogin, setStudentNumberLogin] = useState(''); 
  const [alumniFirstName, setAlumniFirstName] = useState('');
  const [alumniLastName, setAlumniLastName] = useState('');
  const [birthdatePassword, setBirthdatePassword] = useState(''); 
  const [loginError, setLoginError] = useState('');
