import React, { useState, useEffect } from 'react';
import { supabase } from '../lib/supabaseClient';
import { extractDataFromDocument, extractDataFromID } from '../services/geminiService';
import { Student, ExtractedData, UserType, Admin } from '../types';
import FileUpload from './FileUpload';
import { Eye, EyeOff, CheckCircle, AlertCircle, Loader2, XCircle, ArrowRight, ShieldCheck, Edit2, GraduationCap, User, ArrowLeft, Users, HelpCircle, FileText, ScanLine, Lock } from 'lucide-react';

interface AuthPageProps {
  onLoginSuccess: (student: Student) => void;
  onAdminLoginSuccess: (admin: Admin) => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ onLoginSuccess, onAdminLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);

  // Login Success Animation State
  const [showSuccessAnim, setShowSuccessAnim] = useState(false);
  const [loggedInStudentName, setLoggedInStudentName] = useState('');

  // Admin State
  const [isAdminMode, setIsAdminMode] = useState(false);
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');

  // Login State
  const [loginType, setLoginType] = useState<'student' | 'alumni'>('student');
  const [studentNumberLogin, setStudentNumberLogin] = useState(''); 
  const [alumniFirstName, setAlumniFirstName] = useState('');
  const [alumniLastName, setAlumniLastName] = useState('');
  const [birthdatePassword, setBirthdatePassword] = useState(''); 
  const [loginError, setLoginError] = useState('');
  const [showPassword, setShowPassword] = useState(false);

  // Signup Flow State
  const [userType, setUserType] = useState<UserType | null>(null);
  const [extractedData, setExtractedData] = useState<ExtractedData | null>(null);
  const [formData, setFormData] = useState<Partial<ExtractedData>>({});
  const [signupStep, setSignupStep] = useState<'type-select' | 'upload-proof' | 'review-data' | 'upload-id'>('type-select');
  const [signupError, setSignupError] = useState('');
  const [statusMessage, setStatusMessage] = useState('');

  // UI State
  const [showHelp, setShowHelp] = useState(false);

  // Helper: Strict Date Validation (MM-DD-YYYY)
  const isValidDateFormat = (dateString: string) => {
    // Regex matches 01-12 for month, 01-31 for day, and 4 digits for year
    const regex = /^(0[1-9]|1[0-2])-(0[1-9]|[12][0-9]|3[01])-\d{4}$/;
    return regex.test(dateString);
  };

  // Update formData when extractedData changes
  useEffect(() => {
    if (extractedData) {
      setFormData(extractedData);
    }
  }, [extractedData]);

  const handleInputChange = (field: keyof ExtractedData, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleUserTypeSelect = (type: UserType) => {
      setUserType(type);
      setSignupStep('upload-proof');
      setSignupError('');
  };

  const handleBackToTypeSelect = () => {
      setSignupStep('type-select');
      setUserType(null);
      setSignupError('');
      setExtractedData(null);
  };

  // Step 1: Process the Proof of Status (Reg Form or Diploma)
  const handleProofProcess = async (file: File) => {
    setLoading(true);
    setSignupError('');
    setStatusMessage("Analyzing document...");
    try {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = async () => {
        const base64Data = reader.result as string;
        const cleanBase64 = base64Data.split(',')[1];

        try {
          if (!userType) throw new Error("User type not selected");

          const data = await extractDataFromDocument(cleanBase64, file.type, userType);

          // --- VALIDATION LOGIC ---
          const schoolName = data.school_name?.toLowerCase().trim() || "";
          if (!schoolName.includes('laguna university') && !schoolName.includes('laguna univ')) {
            console.warn("Rejected Institution:", schoolName);
            throw new Error(`INVALID INSTITUTION: The document appears to be from "${data.school_name || 'Unknown'}", but only Laguna University documents are accepted.`);
          }

          if (userType === 'graduating') {
              const yearLevel = data.year_level?.toLowerCase().trim() || "";
              const isFourthYear = ['4', 'iv', 'fourth', '4th'].some(term => yearLevel.includes(term));
              if (!isFourthYear) {
                throw new Error(`ELIGIBILITY ERROR: Registration is denied. This system is exclusively for 4th Year graduating students.`);
              }
          }

          setExtractedData(data);
          setSignupStep('review-data');
        } catch (err: any) {
          setSignupError(err.message || "Could not extract data. Ensure the image is clear.");
        } finally {
          setLoading(false);
          setStatusMessage("");
        }
      };
    } catch (err) {
      setSignupError("Error processing file.");
      setLoading(false);
      setStatusMessage("");
    }
  };

  // Step 2: Confirm Data and move to ID Upload
  const handleDataConfirmation = () => {
     if (!formData.student_number || !formData.first_name || !formData.last_name) {
         setSignupError("Critical information is missing. Please edit the fields.");
         return;
     }

     const currentBirthdate = formData.birthdate?.trim() || "";
     if (!isValidDateFormat(currentBirthdate)) {
         setSignupError("Invalid Birthdate Format. It MUST be MM-DD-YYYY (e.g., 01-25-2000).");
         return;
     }

     setSignupStep('upload-id');
     setSignupError('');
  };

  // Step 3: Process Valid ID and Verify
  const handleIdProcess = async (file: File) => {
    setLoading(true);
    setSignupError('');
    setStatusMessage("Verifying Identity...");

    try {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = async () => {
            const base64Data = reader.result as string;
            const cleanBase64 = base64Data.split(',')[1];

            try {
                const idData = await extractDataFromID(cleanBase64, file.type);

                if (!idData.is_valid) {
                    throw new Error("The uploaded image does not appear to be a valid ID.");
                }

                // --- IDENTITY MATCHING LOGIC ---
                // Normalize strings for comparison
                const idName = idData.full_name.toLowerCase();
                const formFirstName = formData.first_name?.toLowerCase() || "";
                const formLastName = formData.last_name?.toLowerCase() || "";

                // Check if the names from the form appear in the ID
                const matchFirst = idName.includes(formFirstName);
                const matchLast = idName.includes(formLastName);

                if (!matchFirst || !matchLast) {
                    throw new Error(`Identity Mismatch: The name on the ID (${idData.full_name}) does not match the name on the document (${formData.first_name} ${formData.last_name}).`);
                }

                // If Matched, proceed directly to Registration
                setStatusMessage("Identity Verified. Creating Account...");
                await executeRegistration();

            } catch (err: any) {
                setSignupError(err.message || "ID Verification failed.");
                setLoading(false);
                setStatusMessage("");
            } 
        };
    } catch (err) {
        setSignupError("Error processing ID.");
        setLoading(false);
        setStatusMessage("");
    }
  };

  // Automated Registration Function (Direct DB Insert)
  const executeRegistration = async () => {
    if (!formData.student_number || !formData.birthdate) {
        setSignupError("Registration Error: Missing extracted data fields.");
        setLoading(false);
        return;
    }

    try {
      const cleanEmail = formData.email?.toLowerCase().trim() || "";
      const cleanPassword = formData.birthdate.trim(); // Using birthdate as password concept
      const cleanStudentNumber = formData.student_number.trim();

      // Final strict format check before database insert
      if (!isValidDateFormat(cleanPassword)) {
         throw new Error("Birthdate format mismatch. Account cannot be created. Please restart and ensure MM-DD-YYYY format.");
      }

      const finalData = { ...extractedData, ...formData };

      // Prepare payload
      const studentPayload = {
         student_number: cleanStudentNumber,
         first_name: finalData.first_name, 
         last_name: finalData.last_name,
         middle_name: finalData.middle_name,
         program: finalData.program,
         gender: finalData.gender,
         email: cleanEmail,
         contact_no: finalData.contact_no,
         address: finalData.address,
         civil_status: finalData.civil_status,
         year_level: finalData.year_level,
         birthdate: cleanPassword, // Storing birthdate as plain text for this tracer logic
         enrollment_status: userType === 'graduating' ? 'Graduating' : 'Alumni'
      };

      // DETERMINING TABLE BASED ON USER TYPE
      const targetTable = userType === 'graduating' ? 'students' : 'alumni';

      // 1. Check if user already exists in the specific table
      const { data: existingUser } = await supabase
        .from(targetTable)
        .select('student_number')
        .eq('student_number', cleanStudentNumber)
        .single();

      if (existingUser) {
          throw new Error("This student number is already registered in our " + targetTable + " records. Please log in.");
      }

      // 2. Direct Insert into Database (Bypassing Auth Provider)
      const { data: insertedData, error: insertError } = await supabase
        .from(targetTable)
        .insert([studentPayload])
        .select()
        .single();

      if (insertError) throw new Error(insertError.message);

      // SUCCESS PATH
      setLoggedInStudentName(finalData.first_name || "User");
      setShowSuccessAnim(true);

      const studentWithSource = { ...insertedData, table_source: targetTable } as Student;

      // Auto Login after delay
      setTimeout(() => {
          onLoginSuccess(studentWithSource);
      }, 2000);

    } catch (err: any) {
      console.error(err);
      setSignupError(err.message || "Registration failed. Database error.");
      setLoading(false);
      setStatusMessage("");
    }
  };

  const handleAdminLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setLoginError('');

    try {
        const { data: adminData, error } = await supabase
            .from('admins')
            .select('*')
            .eq('username', adminUsername)
            .eq('password', adminPassword) // NOTE: In production, verify hash, don't query cleartext!
            .single();

        if (error) {
           console.error("Admin DB Error:", error);
           throw new Error(error.message || "Database error");
        }

        if (!adminData) {
            throw new Error("Invalid Administrator Credentials.");
        }

        setLoggedInStudentName("Admin");
        setShowSuccessAnim(true);
        setTimeout(() => {
            onAdminLoginSuccess({
                id: adminData.id,
                username: adminData.username
            });
        }, 1500);

    } catch (err: any) {
        setLoginError(err.message || "Admin Login Failed");
        setLoading(false);
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setLoginError('');

    try {
      const cleanBirthdate = birthdatePassword.trim(); // This is the password

      // Strict Format Check for Login
      if (!isValidDateFormat(cleanBirthdate)) {
          throw new Error("Invalid Format. Password (Birthdate) must be strictly MM-DD-YYYY (e.g. 01-25-2000).");
      }

      // DETERMINING TABLE BASED ON LOGIN TYPE
      // 'student' -> New Alumni (students table)
      // 'alumni' -> Old Alumni (alumni table)
      const targetTable = loginType === 'student' ? 'students' : 'alumni';
      let query = supabase.from(targetTable).select('*');

      // 1. Build Query based on Login Type
      if (loginType === 'student') {
        const cleanStudentNumber = studentNumberLogin.trim();
        if (!cleanStudentNumber) throw new Error("Please enter your Student Number.");
        query = query.eq('student_number', cleanStudentNumber);
      } else {
        // Alumni Login by Name
        const cleanFirstName = alumniFirstName.trim();
        const cleanLastName = alumniLastName.trim();

        if (!cleanFirstName || !cleanLastName) {
            throw new Error("Please enter your full name.");
        }
        query = query.ilike('first_name', cleanFirstName).ilike('last_name', cleanLastName);
      }

      // 2. Verify Credentials (Direct DB Check)
      const { data: students, error } = await query;

      if (error) {
          console.error("Supabase Login Error:", error);
          throw new Error(error.message || "Database connection failed.");
      }

      if (!students || students.length === 0) {
         throw new Error(`Record not found in ${loginType === 'student' ? 'New Alumni' : 'Old Alumni'} records. Please register first.`);
      }

      // Find the specific student that matches the birthdate
      const matchedStudent = students.find(s => {
          // Direct match (if stored as text "MM-DD-YYYY")
          if (s.birthdate === cleanBirthdate) return true;

          // ISO match (if stored as Date "YYYY-MM-DD")
          const parts = cleanBirthdate.split('-');
          if (parts.length === 3) {
             const isoDate = `${parts[2]}-${parts[0]}-${parts[1]}`;
             if (s.birthdate === isoDate) return true;
          }

          return false;
      });

      if (!matchedStudent) {
          throw new Error("Invalid Credentials. Please check your Birthdate (MM-DD-YYYY).");
      }

      // --- NEW FEATURE: ALUMNI APPROVAL CHECK ---
      // Only for New Alumni (students table)
      if (loginType === 'student') {
        if (matchedStudent.enrollment_status !== 'Alumni') {
           throw new Error("You are not an alumni yet. Please wait for the approval email.");
        }
      }

      // 3. Login Success
      setLoggedInStudentName(matchedStudent.first_name);
      setShowSuccessAnim(true);

      const studentWithSource = { ...matchedStudent, table_source: targetTable } as Student;

      setTimeout(() => {
        onLoginSuccess(studentWithSource);
      }, 3500);

    } catch (err: any) {
      console.error("Login Error Catch:", err);
      let msg = "Login failed due to an unexpected error.";

      if (typeof err === 'string') {
          msg = err;
      } else if (err instanceof Error) {
          msg = err.message;
      } else if (typeof err === 'object' && err !== null) {
          // Attempt to extract message from object if it's not an Error instance
          msg = err.message || err.error_description || JSON.stringify(err);
      }

      setLoginError(msg);
      setLoading(false);
    }
  };

  const toggleAuth = () => {
    setIsLogin(!isLogin);
    setLoginError('');
    setSignupError('');
    setExtractedData(null);
    setFormData({});
    setSignupStep('type-select');
    setUserType(null);
    setStatusMessage("");
    setIsAdminMode(false);
  };

  if (showSuccessAnim) {
    return (
      <div className="fixed inset-0 z-50 flex flex-col items-center justify-center bg-white px-4">
        <div className="absolute inset-0 bg-green-50 bg-opacity-50 backdrop-blur-sm"></div>
        <div className="relative flex flex-col items-center animate-slide-up z-10 p-10 bg-white/90 backdrop-blur-xl rounded-3xl shadow-2xl max-w-sm w-full border border-white/50">
           <div className="w-24 h-24 mb-6 bg-green-100 rounded-full flex items-center justify-center relative shadow-inner">
             <div className="absolute inset-0 rounded-full border-4 border-luGreen opacity-30 animate-ping"></div>
             <CheckCircle className="w-12 h-12 text-luGreen" />
           </div>
           <h2 className="text-3xl font-bold text-gray-800 mb-2 text-center font-display">Welcome Back!</h2>
           <p className="text-xl text-luGold-dark font-medium mb-8 text-center">{loggedInStudentName}</p>
           <div className="flex items-center space-x-3 text-sm text-gray-500 bg-gray-100 px-4 py-2 rounded-full">
              <Loader2 className="w-4 h-4 animate-spin text-luGreen" />
              <span>Redirecting...</span>
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 relative overflow-hidden flex flex-col font-sans selection:bg-luGreen selection:text-white">

      {/* Help Modal */}
      {showHelp && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={() => setShowHelp(false)}></div>
            <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg relative z-10 overflow-hidden animate-slide-up">
                <div className="bg-gradient-to-r from-luGreen to-luGreen-dark p-6 text-white relative">
                    <h3 className="text-2xl font-bold font-display">How it Works</h3>
                    <p className="opacity-80 text-sm mt-1">AI-Powered Registration System</p>
                    <button onClick={() => setShowHelp(false)} className="absolute top-4 right-4 bg-white/20 hover:bg-white/30 p-2 rounded-full transition-colors">
                        <XCircle size={20} />
                    </button>
                </div>
                <div className="p-6 space-y-6">
                    <div className="bg-green-50 p-4 rounded-xl border border-green-100">
                        <h4 className="font-bold text-luGreen text-sm uppercase tracking-wide mb-2">Account Categories</h4>
                        <ul className="text-sm text-gray-600 space-y-2">
                            <li className="flex items-start gap-2">
                                <span className="text-luGold-dark font-bold">•</span>
                                <span><strong>New Alumni:</strong> Refers to graduates from the Class of 2026 onwards, including currently graduating students.</span>
                            </li>
                            <li className="flex items-start gap-2">
                                <span className="text-luGold-dark font-bold">•</span>
                                <span><strong>Old Alumni:</strong> Refers to graduates from the Class of 2025 and prior years.</span>
                            </li>
                        </ul>
                    </div>

                    <div className="flex gap-4">
                        <div className="w-10 h-10 rounded-full bg-blue-50 flex items-center justify-center flex-shrink-0 text-blue-600">
                            <FileText size={20} />
                        </div>
                        <div>
                            <h4 className="font-bold text-gray-800">1. Upload Document</h4>
                            <p className="text-sm text-gray-600 leading-relaxed mt-1">Upload your Certificate of Registration (New Alumni) or Diploma/TOR (Old Alumni).</p>
                        </div>
                    </div>
                    <div className="flex gap-4">
                        <div className="w-10 h-10 rounded-full bg-green-50 flex items-center justify-center flex-shrink-0 text-luGreen">
                            <ShieldCheck size={20} />
                        </div>
                        <div>
                            <h4 className="font-bold text-gray-800">2. Verify & Secure</h4>
                            <p className="text-sm text-gray-600 leading-relaxed mt-1">Our AI extracts your info. Upload a valid ID to match identities and create your secure account.</p>
                        </div>
                    </div>
                </div>
                <div className="p-4 bg-gray-50 text-center border-t border-gray-100">
                    <button onClick={() => setShowHelp(false)} className="text-luGreen font-bold text-sm hover:underline">
                        Got it, thanks!
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* Modern Background with Blobs */}
      <div className="absolute inset-0 w-full h-full overflow-hidden bg-gradient-to-br from-green-50 via-white to-yellow-50">
         <div className="absolute top-0 -left-4 w-72 h-72 bg-luGreen-light rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-blob"></div>
         <div className="absolute top-0 -right-4 w-72 h-72 bg-luGold rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-blob animation-delay-2000"></div>
         <div className="absolute -bottom-8 left-20 w-72 h-72 bg-emerald-200 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-blob animation-delay-4000"></div>
         <div className="absolute inset-0 z-0 opacity-[0.03]" style={{ 
            backgroundImage: `radial-gradient(#004d00 1px, transparent 1px)`,
            backgroundSize: '24px 24px' 
         }}></div>
      </div>

      {/* Help Button Absolute Position */}
      <button 
        onClick={() => setShowHelp(true)}
        className="absolute top-6 right-6 z-20 flex items-center gap-2 bg-white/80 backdrop-blur-md px-4 py-2 rounded-full shadow-sm hover:shadow-md transition-all text-sm font-semibold text-luGreen hover:text-luGreen-dark cursor-pointer border border-green-100"
      >
        <HelpCircle size={18} />
        <span className="hidden sm:inline">How it works</span>
      </button>

      {/* Main Content Area */}
      <div className="flex-grow container mx-auto px-4 z-10 flex flex-col xl:flex-row items-center justify-center gap-12 xl:gap-20 min-h-screen py-8">

        {/* Left Side: Landing Hero Text */}
        <div className="w-full xl:w-5/12 text-center xl:text-left space-y-8 relative animate-slide-up">
            <div className="inline-flex items-center space-x-2 px-4 py-2 rounded-full bg-white/60 backdrop-blur-md border border-green-100 text-luGreen-dark font-semibold text-xs md:text-sm shadow-sm hover:shadow-md transition-shadow cursor-default">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-luGold opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-luGold-dark"></span>
              </span>
              <span>Official Alumni Portal</span>
            </div>

            <h1 className="text-5xl md:text-6xl lg:text-7xl font-bold font-display leading-tight tracking-tight text-gray-900">
              Laguna <span className="text-luGreen">University</span> <br/>
              <span className="text-4xl md:text-5xl lg:text-6xl text-transparent bg-clip-text bg-gradient-to-r from-luGold-dark to-yellow-500">Alumni Tracer</span>
            </h1>

            <div className="space-y-4">
              <p className="text-xl md:text-2xl font-light text-gray-600 tracking-wide flex flex-col md:flex-row items-center xl:items-start gap-2">
                  <span>Powered by</span>
                  <span className="bg-gray-900 text-white px-3 py-1 text-sm font-bold rounded">Machine Learning</span>
                  <span className="text-gray-400 hidden md:inline">&</span>
                  <span className="bg-luGreen text-white px-3 py-1 text-sm font-bold rounded">Data Mining</span>
              </p>

              <p className="text-base md:text-lg text-gray-600 leading-relaxed max-w-2xl mx-auto xl:mx-0 font-normal border-l-4 border-luGold pl-4">
                Reconnect with your alma mater, update your professional journey, and help us shape the future of education through data-driven insights.
              </p>
            </div>
