                                                            : 'bg-amber-50 text-amber-600 border-amber-100'
                                                        }`}>
                                                            {record.job_alignment}
                                                        </span>
                                                    )}
                                                </div>

                                                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity absolute top-6 right-6 bg-white pl-2">
                                                    <button onClick={() => handleEdit(record)} className="p-2 text-gray-400 hover:text-luGreen hover:bg-green-50 rounded-lg transition-colors" title="Edit">
                                                        <Edit2 size={16} />
                                                    </button>
                                                    <button onClick={() => handleDeleteClick(record.id)} className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors" title="Delete">
                                                        <Trash2 size={16} />
                                                    </button>
                                                </div>
                                            </div>

                                            {/* Main Content: Position & Company */}
                                            <div className="mb-6">
                                                <h4 className="text-xl font-bold text-gray-800 leading-tight mb-1">
