                                            <input 
                                                type="text" 
                                                value={formData.last_name || ''} 
                                                onChange={(e) => handleInputChange('last_name', e.target.value)}
                                                className="w-full bg-white border border-gray-200 rounded p-2 text-xs font-bold"
                                            />
                                        </div>
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-luGreen font-bold block mb-1">Birthdate (Password)</label>
                                        <input 
                                            type="text" 
                                            value={formData.birthdate || ''} 
                                            onChange={(e) => handleInputChange('birthdate', e.target.value)}
                                            className={`w-full bg-white border rounded p-2 text-xs font-bold ${
                                                formData.birthdate && !isValidDateFormat(formData.birthdate) 
                                                ? 'border-red-500 text-red-600 bg-red-50' 
                                                : 'border-gray-200'
                                            }`}
                                            placeholder="MM-DD-YYYY"
                                        />
                                        {formData.birthdate && !isValidDateFormat(formData.birthdate) && (
                                            <p className="text-[10px] text-red-500 mt-1 font-bold">Must be MM-DD-YYYY</p>
