import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, 
  PieChart, Pie, Cell 
} from 'recharts';
import { generateCardInterpretations, CardInterpretations } from '../services/adminAI';
import EducationAnalytics from './EducationAnalytics';
import CommunityAnalytics from './CommunityAnalytics';
import SkillsAnalytics from './SkillsAnalytics';

// --- Configuration ---
const COURSES = [
    "Bachelor of Elementary Education (BEED)",
    "Bachelor of Secondary Education (BSED) English",
    "Bachelor of Secondary Education (BSED) Science",
    "Bachelor of Secondary Education (BSED) Math",
    "Bachelor of Science in Entrepreneurship (BSE)",
    "Bachelor of Science in Tourism Management (BSTM)",
    "Bachelor of Science in Accountancy (BSA)",
    "Bachelor of Science in Accounting Information System (BSAIS)",
    "Bachelor of Science in Computer Science (BSCS)",
    "Bachelor of Science in Information Technology (BSIT)",
    "Bachelor of Science in Mechanical Engineering (BSME)",
    "Bachelor of Arts in Communication (BAC)",
    "Diploma in Midwifery"
];

// Glassmorphism Palette (Vibrant for charts to pop against glass)
const ALIGNMENT_COLORS = ['#6366f1', '#a855f7']; // Indigo, Purple
const JOB_LEVEL_COLORS = ['#3b82f6', '#8b5cf6', '#ec4899', '#10b981']; // Blue, Purple, Pink, Emerald

// --- Types ---
interface AnalyticsState {
  totalRespondents: number;
  employedCount: number;
  unemployedCount: number;
  selfEmployedCount: number;
  retiredCount: number;
  industryData: { name: string; value: number }[];
  unemploymentReasonData: { name: string; value: number }[];
  alignmentReasonData: { name: string; value: number }[];
  retirementReasonData: { name: string; value: number }[];
  jobLevelData: { name: string; value: number }[];
  alignmentRate: { name: string; value: number }[];
}

// Master record type that combines employment info with user profile info
interface MasterRecord {
    employment_status: string;
    industry?: string;
    unemployed_reasons?: string;
    alignment_reason?: string;
    retirement_reason?: string;
    job_alignment?: string;
    current_job_level?: string;
    current_position?: string;
    company_name?: string;
    business_name?: string;

    // Detailed Info for Modal
    company_address?: string;
    business_address?: string;
    date_hired?: string;
    business_duration?: string;
    business_type?: string;
    business_contact_no?: string;
    date_retired?: string;
    last_company?: string;

    // Profile Data
    full_name: string;
    program: string;
    year_level: string; // Batch
}

// Helper Component for Interpretation - Professional Insight Card Style (Refined)
const InterpretationBlock = ({ text, loading }: { text?: string, loading: boolean }) => (
    <div className="mt-auto pt-4 border-t border-indigo-50/50">
        <div className="p-4 bg-gradient-to-br from-indigo-50/90 to-purple-50/90 rounded-xl border border-indigo-100 shadow-sm relative overflow-hidden group">
            <div className="flex gap-3">
                <div className="mt-1 shrink-0">
                    <div className="w-8 h-8 rounded-lg bg-white flex items-center justify-center text-indigo-600 shadow-sm ring-1 ring-indigo-100">
                        <Lightbulb size={16} />
                    </div>
                </div>
                <div className="flex flex-col gap-1 relative z-10">
                    <h5 className="text-[10px] font-bold text-indigo-800 uppercase tracking-widest mt-1">
                       Interpretation
                    </h5>
                    {loading ? (
                        <div className="space-y-2 animate-pulse mt-1">
                            <div className="h-2 bg-indigo-200/50 rounded w-full max-w-[12rem]"></div>
                            <div className="h-2 bg-indigo-200/50 rounded w-full max-w-[18rem]"></div>
                        </div>
                    ) : (
                        <p className="text-xs text-slate-700 font-medium leading-relaxed pr-2">
                            {text || "Data insufficient for analysis."}
                        </p>
                    )}
                </div>
            </div>
        </div>
    </div>
);

const HomePage: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [masterData, setMasterData] = useState<MasterRecord[]>([]);

  // Navigation Tabs
  const [activeTab, setActiveTab] = useState<'employment' | 'education' | 'community' | 'skills'>('employment');

  // Filters
  const [selectedYear, setSelectedYear] = useState<string>('All');
  const [selectedCourse, setSelectedCourse] = useState<string>('All');
  const [availableYears, setAvailableYears] = useState<string[]>([]);

  // Modal State
  const [selectedStatusDetail, setSelectedStatusDetail] = useState<string | null>(null);

  // AI Insights State
  const [interpretations, setInterpretations] = useState<CardInterpretations | null>(null);
  const [loadingInsights, setLoadingInsights] = useState(false);

  // Analytics State (Derived)
  const [analytics, setAnalytics] = useState<AnalyticsState>({
    totalRespondents: 0,
    employedCount: 0,
    unemployedCount: 0,
    selfEmployedCount: 0,
    retiredCount: 0,
    industryData: [],
    unemploymentReasonData: [],
    alignmentReasonData: [],
    retirementReasonData: [],
    jobLevelData: [],
    alignmentRate: []
  });

  // --- 1. Data Fetching (Joins Employment with User Profile) ---
  const fetchData = async () => {
      setLoading(true);
      try {
        const { data: empData, error: empError } = await supabase
            .from('employment_information')
            .select('*');

        if (empError) throw empError;
        if (!empData) return;

        const surveyIds = empData.map(e => e.survey_response_id);
        const { data: surveyData, error: surveyError } = await supabase
            .from('survey_responses')
            .select('id, student_id, alumni_id, respondent_type')
            .in('id', surveyIds);

        if (surveyError) throw surveyError;

        const [ { data: students }, { data: alumni } ] = await Promise.all([
            supabase.from('students').select('id, first_name, last_name, program, year_level'),
            supabase.from('alumni').select('id, first_name, last_name, program, year_level')
        ]);

        const studentMap = new Map(students?.map((s: any) => [s.id, s]));
        const alumniMap = new Map(alumni?.map((a: any) => [a.id, a]));
        const surveyMap = new Map(surveyData?.map((s: any) => [s.id, s]));

        const combined: MasterRecord[] = [];

        empData.forEach(record => {
            const survey = surveyMap.get(record.survey_response_id) as any;
            if (!survey) return;

            let userProfile: any = null;
            if (survey.respondent_type === 'student') {
                userProfile = studentMap.get(survey.student_id);
            } else {
                userProfile = alumniMap.get(survey.alumni_id);
            }

            if (userProfile) {
                const year = userProfile.year_level || 'Unknown';
                const fullName = `${userProfile.last_name}, ${userProfile.first_name}`;

                combined.push({
                    employment_status: record.employment_status,
                    industry: record.industry,
                    unemployed_reasons: record.unemployed_reasons,
                    alignment_reason: record.alignment_reason,
                    retirement_reason: record.retirement_reason,
                    job_alignment: record.job_alignment,
                    current_job_level: record.current_job_level,
                    current_position: record.current_position,
                    company_name: record.company_name,
                    business_name: record.business_name,
                    company_address: record.company_address,
                    business_address: record.business_address,
                    date_hired: record.date_hired,
                    business_duration: record.business_duration,
                    business_type: record.business_type,
                    business_contact_no: record.business_contact_no,
                    date_retired: record.date_retired,
                    last_company: record.last_company,
                    full_name: fullName,
                    program: userProfile.program || 'Unknown',
                    year_level: year
                });
            }
        });

        const staticYears = [];
        for (let y = 2026; y >= 2006; y--) {
            staticYears.push(y.toString());
        }
        setAvailableYears(staticYears);

        setMasterData(combined);

      } catch (err) {
          console.error("Data fetch error:", err);
      } finally {
          setLoading(false);
      }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- 2. Filter Logic & Calculation ---
  useEffect(() => {
    const filtered = masterData.filter(record => {
        const matchesYear = selectedYear === 'All' || record.year_level === selectedYear;
        const matchesCourse = selectedCourse === 'All' || record.program === selectedCourse;
        return matchesYear && matchesCourse;
    });

    const total = filtered.length;
    const employed = filtered.filter(r => r.employment_status === 'Employed').length;
    const selfEmployed = filtered.filter(r => r.employment_status === 'Self-employed').length;
    const unemployed = filtered.filter(r => r.employment_status === 'Unemployed').length;
    const retired = filtered.filter(r => r.employment_status === 'Retired').length;

    const industryMap: Record<string, number> = {};
    const unempReasonMap: Record<string, number> = {};
    const misalignMap: Record<string, number> = {};
    const retireMap: Record<string, number> = {};
    const jobLevelMap: Record<string, number> = {};

    let relatedCount = 0;
    let nonRelatedCount = 0;

    filtered.forEach(r => {
        if (r.industry) industryMap[r.industry] = (industryMap[r.industry] || 0) + 1;
        if (r.unemployed_reasons) unempReasonMap[r.unemployed_reasons] = (unempReasonMap[r.unemployed_reasons] || 0) + 1;
        if (r.alignment_reason) misalignMap[r.alignment_reason] = (misalignMap[r.alignment_reason] || 0) + 1;
        if (r.retirement_reason) retireMap[r.retirement_reason] = (retireMap[r.retirement_reason] || 0) + 1;
        if (r.current_job_level && r.current_job_level !== 'N/A') {
             jobLevelMap[r.current_job_level] = (jobLevelMap[r.current_job_level] || 0) + 1;
        }
        if (r.job_alignment === 'Related') relatedCount++;
        if (r.job_alignment === 'Non-Related') nonRelatedCount++;
    });

    const formatChartData = (map: Record<string, number>, topN = 5) => 
        Object.entries(map)
            .map(([name, value]) => ({ name, value }))
            .sort((a, b) => b.value - a.value)
            .slice(0, topN);

    const calculatedAnalytics = {
        totalRespondents: total,
        employedCount: employed,
        selfEmployedCount: selfEmployed,
        unemployedCount: unemployed,
        retiredCount: retired,
        industryData: formatChartData(industryMap),
        unemploymentReasonData: formatChartData(unempReasonMap),
        alignmentReasonData: formatChartData(misalignMap),
        retirementReasonData: formatChartData(retireMap),
        jobLevelData: formatChartData(jobLevelMap),
        alignmentRate: [
            { name: 'Related', value: relatedCount },
            { name: 'Non-Related', value: nonRelatedCount }
        ]
    };

    setAnalytics(calculatedAnalytics);

    if (total > 0 && activeTab === 'employment') {
        const fetchInsights = async () => {
            setLoadingInsights(true);
            const context = {
                year: selectedYear === 'All' ? 'All' : selectedYear,
                course: selectedCourse === 'All' ? 'All' : selectedCourse
            };
            const data = await generateCardInterpretations(calculatedAnalytics, context);
            // Combined interpretation for alignment + misalignment
            if (data) {
                const combinedAlignment = `${data.alignment} ${data.misalignment}`;
                setInterpretations({ ...data, alignment: combinedAlignment });
            }
            setLoadingInsights(false);
        };
        fetchInsights();
    }

  }, [masterData, selectedYear, selectedCourse, activeTab]);

  const modalData = useMemo(() => {
    if (!selectedStatusDetail) return [];
    return masterData.filter(record => {
        const matchesStatus = record.employment_status === selectedStatusDetail;
        const matchesYear = selectedYear === 'All' || record.year_level === selectedYear;
        const matchesCourse = selectedCourse === 'All' || record.program === selectedCourse;
        return matchesStatus && matchesYear && matchesCourse;
    });
  }, [selectedStatusDetail, masterData, selectedYear, selectedCourse]);

  const getPercent = (count: number) => {
      if (analytics.totalRespondents === 0) return 0;
      return Math.round((count / analytics.totalRespondents) * 100);
  };

  const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
    const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
    const x = cx + radius * Math.cos(-midAngle * (Math.PI / 180));
    const y = cy + radius * Math.sin(-midAngle * (Math.PI / 180));

    return (
      <text x={x} y={y} fill="white" textAnchor="middle" dominantBaseline="central" className="text-[10px] font-bold pointer-events-none">
        {`${(percent * 100).toFixed(0)}%`}
      </text>
    );
  };

  const handlePrint = () => {
    window.print();
  };

  // Glass List Card (Refactored for Layout Symmetry)
  const ReasonListCard = ({ 
    title, 
    icon: Icon, 
    data, 
    colorClass, 
    barColorClass, 
    interpretation,
    embedded = false
  }: { 
    title: string, 
    icon: any, 
    data: { name: string, value: number }[],
    colorClass: string,
    barColorClass: string,
    interpretation?: string,
    embedded?: boolean
  }) => {
    const maxValue = Math.max(...data.map(d => d.value), 1);

    return (
        <div className={`flex flex-col h-full hover:bg-white/60 transition-all duration-300 ${!embedded ? 'bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 rounded-2xl' : 'bg-transparent'}`}>
            <div className={`${embedded ? 'p-0' : 'p-6 flex-grow'}`}>
                {title && (
                    <div className={`flex items-center gap-3 mb-4 pb-2 ${!embedded ? 'border-b border-white/30' : ''}`}>
                        <div className={`p-2 rounded-xl bg-white/60 shadow-sm ${embedded ? 'text-purple-600' : 'text-indigo-600'}`}>
                            <Icon size={20}/>
                        </div>
                        <h4 className="font-bold text-slate-800">{title}</h4>
                    </div>
                )}

                <div className="space-y-4 mb-2">
                    {data.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-32 text-slate-400">
                            <AlertCircle size={24} className="mb-2 opacity-50" />
                            <p className="text-xs font-bold uppercase tracking-wider">No data</p>
                        </div>
                    ) : (
                        data.map((item, index) => (
                            <div key={index} className="group">
                                <div className="flex justify-between items-center mb-1">
                                    <span className={`text-[10px] font-bold text-slate-500 bg-white/60 px-2 py-0.5 rounded-md min-w-[24px] text-center mr-3 shadow-sm border ${embedded ? 'border-purple-100' : 'border-white/40'}`}>#{index + 1}</span>
                                    <span className="text-sm font-semibold text-slate-700 flex-grow truncate mr-4" title={item.name}>
                                        {item.name}
                                    </span>
                                    <span className="text-sm font-bold text-slate-900">{item.value}</span>
                                </div>
                                <div className={`w-full bg-white/40 rounded-full h-1.5 overflow-hidden ${embedded ? 'bg-purple-100' : ''}`}>
                                    <div 
                                        className={`h-full rounded-full ${embedded ? 'bg-gradient-to-r from-purple-500 to-pink-500' : 'bg-gradient-to-r from-blue-400 to-indigo-500'}`} 
                                        style={{ width: `${(item.value / maxValue) * 100}%` }}
                                    ></div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>

            {!embedded && (
                <div className="px-6 pb-6">
                    <InterpretationBlock text={interpretation} loading={loadingInsights} />
                </div>
            )}
        </div>
    );
  };

  return (
    <div className="space-y-8 animate-fade-in pb-10 relative">
        <style>
          {`
            @media print {
              body * { visibility: hidden; }
              #printable-modal, #printable-modal * { visibility: visible; }
              #printable-modal { position: fixed; left: 0; top: 0; width: 100%; height: 100%; background: white; z-index: 9999; padding: 0; margin: 0; }
              .no-print { display: none !important; }
              table { width: 100%; border-collapse: collapse; }
              th, td { border: 1px solid #ddd; padding: 8px; font-size: 10px; color: black; }
              thead { background-color: #eee; -webkit-print-color-adjust: exact; }
            }
          `}
        </style>

        {/* === GLASSMORPHISM MODAL (ENHANCED) === */}
        {selectedStatusDetail && (
            <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 print:p-0">
                <div 
                    className="absolute inset-0 bg-slate-200/60 backdrop-blur-3xl animate-in fade-in duration-300 no-print"
                    onClick={() => setSelectedStatusDetail(null)}
                ></div>
                <div id="printable-modal" className="bg-white/80 backdrop-blur-2xl rounded-3xl border border-white/60 shadow-2xl w-full max-w-7xl h-[85vh] relative z-10 flex flex-col animate-in zoom-in-95 duration-300 overflow-hidden ring-1 ring-white/40">
                    <div className="p-6 border-b border-white/40 flex justify-between items-center bg-white/40 backdrop-blur-md sticky top-0 z-20">
                        <div className="flex items-center gap-4">
                            <div className="p-4 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-2xl text-white shadow-xl shadow-indigo-500/20 no-print">
                                {selectedStatusDetail === 'Employed' && <Briefcase size={28} />}
                                {selectedStatusDetail === 'Unemployed' && <AlertCircle size={28} />}
                                {selectedStatusDetail === 'Self-employed' && <Building2 size={28} />}
                                {selectedStatusDetail === 'Retired' && <UserCheck size={28} />}
                            </div>
                            <div>
                                <h3 className="text-3xl font-black text-slate-800 tracking-tight">{selectedStatusDetail} List</h3>
                                <p className="text-sm text-slate-500 font-bold mt-1">
                                    Showing <span className="text-indigo-600">{modalData.length} records</span> • {selectedYear === 'All' ? 'All Batches' : `Batch ${selectedYear}`} • {selectedCourse === 'All' ? 'All Programs' : 'Selected Program'}
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-3 no-print">
                            <button onClick={handlePrint} className="flex items-center gap-2 px-5 py-2.5 bg-slate-800 text-white rounded-xl text-sm font-bold shadow-lg hover:bg-slate-900 hover:shadow-xl hover:-translate-y-0.5 transition-all">
                                <Printer size={18} /> Print Report
                            </button>
                            <button onClick={() => setSelectedStatusDetail(null)} className="p-2.5 bg-white/60 border border-white/50 rounded-xl hover:bg-red-50 hover:text-red-500 hover:border-red-200 transition-all shadow-sm text-slate-400">
                                <X size={24} />
                            </button>
                        </div>
                    </div>

                    <div className="flex-grow overflow-auto p-0 bg-white/20">
                        {modalData.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-full text-slate-400 py-20">
                                <div className="p-6 bg-white/40 rounded-full mb-4">
                                    <Users size={48} className="opacity-50" />
                                </div>
                                <p className="font-bold text-lg">No records found matching current filters.</p>
                            </div>
                        ) : (
                            <div className="w-full">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-slate-50/90 sticky top-0 z-10 backdrop-blur-md shadow-sm">
                                        <tr>
                                            <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50 w-1/4">Alumni Profile</th>
                                            {selectedStatusDetail === 'Employed' && (
                                                <>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Position & Level</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Company & Industry</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Details</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50 text-center">Alignment</th>
                                                </>
                                            )}
                                            {selectedStatusDetail === 'Self-employed' && (
                                                <>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Business Name & Type</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Address</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Duration</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50 text-center">Alignment</th>
                                                </>
                                            )}
                                            {selectedStatusDetail === 'Unemployed' && (
                                                <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Reason Provided</th>
                                            )}
                                            {selectedStatusDetail === 'Retired' && (
                                                <>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Retirement Info</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Previous Company</th>
                                                </>
                                            )}
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-indigo-50/50">
                                        {modalData.map((record, idx) => (
                                            <tr key={idx} className="hover:bg-indigo-50/40 transition-colors group">
                                                <td className="p-5 align-top">
                                                    <div className="flex items-start gap-3">
                                                        <div className="w-10 h-10 rounded-full bg-gradient-to-br from-slate-200 to-slate-300 flex items-center justify-center text-slate-600 font-bold text-xs shadow-inner">
                                                            {record.full_name.charAt(0)}
                                                        </div>
                                                        <div>
                                                            <div className="font-bold text-slate-800 text-sm">{record.full_name}</div>
                                                            <div className="text-xs text-slate-500 font-medium mt-0.5">{record.program}</div>
                                                            <div className="inline-block mt-2 px-2 py-0.5 bg-white border border-slate-200 text-slate-600 rounded text-[10px] font-bold shadow-sm">
                                                                Batch {record.year_level}
                                                            </div>
                                                        </div>
                                                    </div>
                                                </td>
                                                {selectedStatusDetail === 'Employed' && (
                                                    <>
                                                        <td className="p-5 align-top">
                                                            <div className="font-bold text-slate-700 text-sm">{record.current_position || 'N/A'}</div>
                                                            <div className="text-xs text-indigo-500 font-bold mt-1 flex items-center gap-1 bg-indigo-50 px-2 py-1 rounded w-fit">
                                                                <Award size={12} /> {record.current_job_level || 'Unclassified'}
                                                            </div>
                                                        </td>
                                                        <td className="p-5 align-top">
                                                            <div className="font-bold text-slate-700 text-sm">{record.company_name}</div>
                                                            <div className="text-xs text-slate-500 mt-1 flex items-center gap-1">
                                                                <Building2 size={12}/> {record.industry || 'N/A'}
                                                            </div>
                                                        </td>
                                                        <td className="p-5 align-top">
                                                            <div className="text-xs text-slate-600 space-y-1">
                                                                <div className="flex items-center gap-1"><MapPin size={12} className="text-slate-400"/> {record.company_address || 'N/A'}</div>
                                                                <div className="flex items-center gap-1"><Calendar size={12} className="text-slate-400"/> Hired: {record.date_hired || 'N/A'}</div>
                                                            </div>
                                                        </td>
                                                        <td className="p-5 align-top text-center">
                                                            <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-[10px] font-bold uppercase shadow-sm border ${
                                                                record.job_alignment === 'Related' 
                                                                ? 'bg-green-100 text-green-700 border-green-200' 
                                                                : 'bg-amber-100 text-amber-700 border-amber-200'
                                                            }`}>
                                                                {record.job_alignment === 'Related' ? <CheckCircle2 size={12}/> : <XCircle size={12}/>}
                                                                {record.job_alignment || 'N/A'}
                                                            </span>
                                                        </td>
                                                    </>
                                                )}
                                                 {selectedStatusDetail === 'Self-employed' && (
                                                    <>
                                                        <td className="p-5 align-top">
                                                            <div className="font-bold text-slate-700 text-sm">{record.business_name}</div>
                                                            <div className="text-xs text-slate-500 mt-1">{record.business_type || 'Type not specified'}</div>
                                                        </td>
                                                        <td className="p-5 align-top">
                                                            <div className="text-xs text-slate-600 flex items-center gap-1">
                                                                <MapPin size={12} className="text-slate-400"/> {record.business_address}
