export const sendApprovalEmail = async (toName: string, toEmail: string, course: string) => {
  try {
    const templateParams = {
      to_name: toName,
      to_email: toEmail,
      course: course,
      from_name: 'Laguna University Alumni System',
      message: `Congratulations! Your alumni account has been approved. You can now log in to the Alumni Tracer System to update your profile and employment status.`,
      subject: 'Alumni Account Approved',
      reply_to: 'placement.alumni.linkages@gmail.com'
    };

    const response = await emailjs.send(
      SERVICE_ID,
      TEMPLATE_ID,
      templateParams
    );

    return { success: true, response };
  } catch (error) {
    console.error('EmailJS Error:', error);
    return { success: false, error };
  }
};

import React, { useState, useEffect } from 'react';
import { GraduationCap, Users, Search, RefreshCw, Trash2, Edit, X, Save, AlertTriangle, Loader2 } from 'lucide-react';
import { supabase } from '../lib/supabaseClient';
import { Student } from '../types';

const UserManagement: React.FC = () => {
  const [userType, setUserType] = useState<'graduating' | 'alumni'>('graduating');
  const [students, setStudents] = useState<Student[]>([]);
  const [loadingUsers, setLoadingUsers] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Modal States
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState<Student | null>(null);
  const [editFormData, setEditFormData] = useState<Partial<Student>>({});
  const [processing, setProcessing] = useState(false);

  const fetchUsers = async () => {
    setLoadingUsers(true);
    const table = userType === 'graduating' ? 'students' : 'alumni';

    const { data, error } = await supabase
      .from(table)
      .select('*')
      .order('last_name', { ascending: true });

    if (!error && data) {
      setStudents(data as Student[]);
    }
    setLoadingUsers(false);
  };

  useEffect(() => {
    fetchUsers();
  }, [userType]);

  const handleEditClick = (student: Student) => {
    setSelectedUser(student);
    setEditFormData({
      first_name: student.first_name,
      last_name: student.last_name,
      student_number: student.student_number,
      program: student.program,
      year_level: student.year_level,
      email: student.email,
      contact_no: student.contact_no
    });
    setIsEditModalOpen(true);
  };

  const handleDeleteClick = (student: Student) => {
    setSelectedUser(student);
    setIsDeleteModalOpen(true);
  };

  const saveEdit = async () => {
    if (!selectedUser) return;
    setProcessing(true);
    try {
      const table = userType === 'graduating' ? 'students' : 'alumni';
      const { error } = await supabase
        .from(table)
        .update(editFormData)
        .eq('id', selectedUser.id);

      if (error) throw error;

      await fetchUsers();
      setIsEditModalOpen(false);
      setSelectedUser(null);
    } catch (err) {
      console.error("Update failed:", err);
      alert("Failed to update record.");
    } finally {
      setProcessing(false);
    }
  };

  const confirmDelete = async () => {
    if (!selectedUser) return;
    setProcessing(true);
    try {
      const table = userType === 'graduating' ? 'students' : 'alumni';
      const { error } = await supabase
        .from(table)
        .delete()
        .eq('id', selectedUser.id);

      if (error) throw error;

      await fetchUsers();
      setIsDeleteModalOpen(false);
      setSelectedUser(null);
    } catch (err) {
      console.error("Delete failed:", err);
      alert("Failed to delete record.");
    } finally {
      setProcessing(false);
    }
  };

  const filteredStudents = students.filter(student => 
    student.last_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.first_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.student_number.includes(searchTerm)
  );

  return (
    <div className="space-y-6 animate-fade-in pb-10">

        {/* --- Header Section (Glass) --- */}
        <div className="flex flex-col xl:flex-row justify-between items-start xl:items-end gap-6 bg-white/40 backdrop-blur-xl p-6 rounded-3xl border border-white/50 shadow-lg shadow-indigo-500/5">
            <div>
                <h2 className="text-2xl font-bold text-slate-800">User Management</h2>
                <p className="text-slate-500 mt-1">Manage new graduates and alumni records.</p>
            </div>

            {/* Action Bar */}
            <div className="flex flex-col sm:flex-row gap-3 w-full xl:w-auto">
                {/* Search */}
                <div className="relative group w-full sm:w-64">
                    <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                    <input 
                        type="text" 
                        placeholder="Search name or ID..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-9 pr-4 py-2.5 rounded-xl bg-white border border-slate-200 text-sm font-semibold text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all shadow-sm"
                    />
                </div>

                {/* Refresh */}
                <button 
                    onClick={fetchUsers}
                    className="p-2.5 bg-white border border-slate-200 text-slate-600 rounded-xl hover:bg-slate-50 hover:text-indigo-600 transition-all shadow-sm"
                    title="Refresh Data"
                >
                    <RefreshCw className={`w-5 h-5 ${loadingUsers ? 'animate-spin' : ''}`} />
                </button>
            </div>
        </div>

        {/* --- Tabs (Glass Pills) --- */}
        <div className="flex gap-4">
            <button 
                onClick={() => setUserType('graduating')}
                className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-sm font-bold transition-all border ${
                    userType === 'graduating' 
                    ? 'bg-gradient-to-r from-green-500 to-emerald-600 text-white shadow-lg shadow-green-500/30 border-transparent' 
                    : 'bg-white/40 border-white/60 text-slate-500 hover:bg-white/60 hover:text-slate-800'
                }`}
            >
                <GraduationCap size={18} /> New Alumni
            </button>
            <button 
                onClick={() => setUserType('alumni')}
                className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-sm font-bold transition-all border ${
                    userType === 'alumni' 
                    ? 'bg-gradient-to-r from-purple-500 to-indigo-600 text-white shadow-lg shadow-purple-500/30 border-transparent' 
                    : 'bg-white/40 border-white/60 text-slate-500 hover:bg-white/60 hover:text-slate-800'
                }`}
            >
                <Users size={18} /> Old Alumni
            </button>
        </div>

        {/* --- Table Section (Glass) --- */}
        <div className="bg-white/40 backdrop-blur-xl rounded-3xl border border-white/50 shadow-lg shadow-indigo-500/5 overflow-hidden min-h-[400px]">
            <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead className="bg-slate-50/80 backdrop-blur-md border-b border-white/50">
                        <tr>
                            <th className="px-6 py-5 text-xs font-bold text-slate-500 uppercase tracking-widest">Student Info</th>
                            <th className="px-6 py-5 text-xs font-bold text-slate-500 uppercase tracking-widest">Program & Batch</th>
                            <th className="px-6 py-5 text-xs font-bold text-slate-500 uppercase tracking-widest">Contact Details</th>
                            <th className="px-6 py-5 text-xs font-bold text-slate-500 uppercase tracking-widest text-center">Status</th>
                            <th className="px-6 py-5 text-xs font-bold text-slate-500 uppercase tracking-widest text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-indigo-50/30">
                        {loadingUsers ? (
                            <tr>
                                <td colSpan={5} className="px-6 py-20 text-center text-slate-400">
                                    <div className="flex flex-col items-center">
                                        <Loader2 className="w-8 h-8 animate-spin mb-2 opacity-50" />
                                        <span className="text-sm font-medium">Loading records...</span>
                                    </div>
                                </td>
                            </tr>
                        ) : filteredStudents.length === 0 ? (
                            <tr>
                                <td colSpan={5} className="px-6 py-20 text-center text-slate-400">
                                    <div className="flex flex-col items-center">
                                        <Users className="w-10 h-10 mb-2 opacity-30" />
                                        <span className="text-sm font-medium">No records found.</span>
                                    </div>
                                </td>
                            </tr>
                        ) : (
                            filteredStudents.map((student, index) => (
                                <tr key={index} className="hover:bg-white/40 transition-colors group">
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-3">
                                            <div className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold text-white shadow-md ${userType === 'graduating' ? 'bg-gradient-to-br from-green-400 to-emerald-500' : 'bg-gradient-to-br from-purple-400 to-indigo-500'}`}>
                                                {student.first_name.charAt(0)}{student.last_name.charAt(0)}
                                            </div>
                                            <div>
                                                <div className="font-bold text-slate-800">{student.last_name}, {student.first_name}</div>
                                                <div className="text-xs font-mono text-slate-500 bg-white/50 px-1.5 py-0.5 rounded border border-white/50 inline-block mt-1">
                                                    {student.student_number}
                                                </div>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="text-sm font-semibold text-slate-700">{student.program}</div>
                                        <div className="text-xs text-slate-500 mt-1">Batch {student.year_level}</div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <div className="text-sm text-slate-600">{student.email || 'No Email'}</div>
                                        <div className="text-xs text-slate-400 mt-0.5">{student.contact_no || 'No Contact'}</div>
                                    </td>
                                    <td className="px-6 py-4 text-center">
                                        <span className={`inline-flex items-center px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border shadow-sm ${
                                            student.enrollment_status === 'Alumni' 
                                            ? 'bg-purple-50 text-purple-700 border-purple-200'
                                            : 'bg-green-50 text-green-700 border-green-200'
                                        }`}>
                                            {student.enrollment_status === 'Alumni' ? 'Verified Alumni' : 'New Graduate'}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button 
                                                onClick={() => handleEditClick(student)}
                                                className="p-2 bg-white border border-slate-200 text-slate-500 rounded-lg hover:bg-indigo-50 hover:text-indigo-600 hover:border-indigo-200 transition-all shadow-sm"
                                                title="Edit User"
                                            >
                                                <Edit size={16} />
                                            </button>
                                            <button 
                                                onClick={() => handleDeleteClick(student)}
                                                className="p-2 bg-white border border-slate-200 text-slate-500 rounded-lg hover:bg-red-50 hover:text-red-600 hover:border-red-200 transition-all shadow-sm"
                                                title="Delete User"
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>

        {/* --- Edit Modal --- */}
        {isEditModalOpen && (
            <div className="fixed inset-0 z-[9999] flex items-center justify-center">
                <div className="absolute inset-0 bg-slate-200/60 backdrop-blur-3xl animate-in fade-in duration-300" onClick={() => setIsEditModalOpen(false)}></div>
                <div className="bg-white/90 backdrop-blur-2xl rounded-3xl shadow-2xl w-full max-w-lg relative z-10 p-8 border border-white/50 animate-in zoom-in-95 duration-300 m-4">
                    <div className="flex justify-between items-center mb-6">
