      .order('last_name', { ascending: true });

    if (!error && data) {
      setStudents(data as Student[]);
    }
    setLoadingUsers(false);
  };

  useEffect(() => {
    fetchUsers();
  }, [userType]);

  const handleEditClick = (student: Student) => {
    setSelectedUser(student);
    setEditFormData({
      first_name: student.first_name,
      last_name: student.last_name,
      student_number: student.student_number,
      program: student.program,
      year_level: student.year_level,
      email: student.email,
      contact_no: student.contact_no
    });
    setIsEditModalOpen(true);
  };

  const handleDeleteClick = (student: Student) => {
    setSelectedUser(student);
    setIsDeleteModalOpen(true);
  };

  const saveEdit = async () => {
    if (!selectedUser) return;
    setProcessing(true);
    try {
      const table = userType === 'graduating' ? 'students' : 'alumni';
      const { error } = await supabase
        .from(table)
        .update(editFormData)
        .eq('id', selectedUser.id);

      if (error) throw error;

      await fetchUsers();
      setIsEditModalOpen(false);
      setSelectedUser(null);
    } catch (err) {
      console.error("Update failed:", err);
      alert("Failed to update record.");
    } finally {
      setProcessing(false);
    }
  };

  const confirmDelete = async () => {
    if (!selectedUser) return;
    setProcessing(true);
    try {
      const table = userType === 'graduating' ? 'students' : 'alumni';
      const { error } = await supabase
        .from(table)
        .delete()
        .eq('id', selectedUser.id);

      if (error) throw error;

      await fetchUsers();
      setIsDeleteModalOpen(false);
      setSelectedUser(null);
    } catch (err) {
      console.error("Delete failed:", err);
      alert("Failed to delete record.");
    } finally {
      setProcessing(false);
    }
  };

  const filteredStudents = students.filter(student => 
    student.last_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.first_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.student_number.includes(searchTerm)
  );

  return (
    <>
    <div className="space-y-6 animate-fade-in pb-10">

        {/* --- Header Section (Glass) --- */}
        <div className="flex flex-col xl:flex-row justify-between items-start xl:items-end gap-6 bg-white/40 backdrop-blur-xl p-6 rounded-3xl border border-white/50 shadow-lg shadow-indigo-500/5">
            <div>
                <h2 className="text-2xl font-bold text-slate-800">User Management</h2>
                <p className="text-slate-500 mt-1">Manage new graduates and alumni records.</p>
