                                                title="Delete User"
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    </div>

        {/* --- Edit Modal --- */}
        {isEditModalOpen && (
            <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-slate-200/60 backdrop-blur-3xl animate-in fade-in duration-300" onClick={() => setIsEditModalOpen(false)}></div>
